{
  "formal_minutes": {
    "decisions": [
      {
        "item": "공개 릴리즈 타깃은 smoke 테스트 통과 시 금요일 15:00 KST로 확정",
        "status": "확정"
      },
      {
        "item": "packageName 불일치 대응은 smoke-theme-pack.mjs에서 무시 처리하지 않음. 우선 패키지 설정을 먼저 확인하고, 계약 자체 오류인 경우에만 스크립트를 재검토",
        "status": "확정"
      },
      {
        "item": "Minjun이 금요일 10:00 KST까지 smoke 재실행 후 결과 공유",
        "status": "확정"
      },
      {
        "item": "Doyun이 금요일 12:00 KST까지 action_items.md에 실패 triage note 작성",
        "status": "확정"
      },
      {
        "item": "Hara가 Minjun의 smoke 결과 공유 후 생성된 tarball 경로 확인",
        "status": "확정"
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara가 제안한 smoke-theme-pack.mjs의 packageName mismatch 무시 로직 변경은 거절",
        "reason": "스크립트 수정보다 package config 점검 및 계약 준수 범위 확립을 우선"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리즈 제안(Seoyeon) 제시됨",
        "scope": "내부 stretch goal로만 유지, 공식 릴리즈 타깃 아님"
      },
      {
        "item": "README 설치 단계 검토를 목요일 가용 시 수행 제안",
        "scope": "내부 점검 제안, 공식 승인된 일정/주체 미확정"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 스텝 검토의 주체(Owner)는 미지정 상태",
        "status": "미결정"
      },
      {
        "item": "Hara의 tarball 경로 확인 기한은 결과 공유 시점 연동으로만 관리",
        "status": "미결정(종속)"
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 release가 지연될 수 있음",
        "impact": "중간~높음"
      },
      {
        "item": "README 설치 단계가 오래되면 릴리즈 노트가 사용자 오도 가능성 있음",
        "impact": "중간"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리즈 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "release note에 내부 수요일 stretch goal(제안 시한) 언급을 포함할지 여부"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정됨",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage note를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "예정됨",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과 공유 후 생성된 tarball 경로 확인",
      "due": "Minjun 결과 공유 후",
      "status": "조건부 예정",
      "source_certainty": "확정"
    },
    {
      "owner": null,
      "task": "README 설치 단계 최신성 점검(내부 제안사항)",
      "due": "목요일 가능 시",
      "status": "미할당/추적 필요",
      "source_certainty": "부분확정"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 smoke 결과 공유 확인",
      "smoke pass 여부에 따라 금요일 15:00 KST 공개 릴리즈 진행 가능성 판단",
      "Hara의 tarball 경로 점검 완료 여부 확인",
      "README 설치 단계 검토 책임자 지정 및 최신성 확인",
      "최종 릴리즈 승인 권한자, release note의 수요일 stretch goal 반영 여부 확정"
    ],
    "do_not_invent": [
      "고객명/외부 파트너명",
      "예산 수치",
      "보안 사고",
      "운영 장애(Outage)",
      "법무 승인 필요성",
      "미확정 Owner 또는 마감일"
    ]
  },
  "non_invention_rules": [
    "회의록에 명시되지 않은 고객·예산·보안·장애·법적 승인·Owner·마감일 정보는 추가하지 않는다.",
    "시간 정보는 회의록에 나온 표현(예: 금요일 10:00 KST, 금요일 12:00 KST, 금요일 15:00 KST, 목요일 가능 시, 결과 공유 후)만 사용한다.",
    "추정 기반 결론을 내리지 않고, 미결정/열린 질문은 열린 상태로 그대로 남긴다.",
    "모든 항목은 단일 소스(제공된 public-safe fixture)에서 직접 추출한 내용으로만 구성한다."
  ]
}
